const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x0c1520);this.add.rectangle(W/2,H*0.62,W,H*0.76,0x1d4e89);this.coins=0;this.power=1;this.ui=this.add.text(10,10,'Coins:0  Power:1');this.btn=this.add.rectangle(W/2,H-70,180,44,0x7dd3fc).setInteractive();this.add.text(W/2,H-78,'낚시!',{fontSize:'24px'}).setOrigin(.5);this.btn.on('pointerdown',()=>this.fish());this.time.addEvent({delay:1200,loop:true,callback:()=>{this.coins+=this.power;this.refresh();}});this.shop=this.add.rectangle(W-70,40,110,34,0xf59e0b).setInteractive();this.add.text(W-70,33,'강화(20)',{fontSize:'14px'}).setOrigin(.5,0);this.shop.on('pointerdown',()=>{if(this.coins>=20){this.coins-=20;this.power++;this.refresh();}});this.r=this.input.keyboard.addKey('R');}fish(){this.coins+=2*this.power;this.refresh();const f=this.add.circle(Phaser.Math.Between(40,W-40),Phaser.Math.Between(H*0.35,H*0.8),6,0xfde68a);this.tweens.add({targets:f,alpha:0,y:-30,duration:500,onComplete:()=>f.destroy()});}refresh(){this.ui.setText(`Coins:${this.coins}  Power:${this.power}`);}update(){if(this.r.isDown)this.scene.restart();}}new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});